const Q_CHEMISTRY_1997=[{"id": "objective>Chemistry>1997>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">35 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of hydrogen was sparked with 12 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of oxygen at 110<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C and 760mm Hg to produce steam. What percentage of the total volume of gas left after the reaction is hydrogen?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">11%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">31%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">35%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">69%</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>+O2→2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O <br/> 2vol:1vol:2vol <br/> Hence, 2 volumes of Hydrogen is needed for the reaction with Oxygen to produce steam (water). <br/>  <br/> ∴12cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>→2×12cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>=24cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> Excess of Hydrogen:35cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>−24cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>=11cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> % Hydrogen left after the reaction=11/35×100 <br/> =31%</div>", "topic": "CHEMICAL COMBINATION : AVOGADRO'S LAW"}, {"id": "objective>Chemistry>1997>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">2.85g of an oxide of copper gave 2.52g of copper on reduction and 1.90g of another oxide gave 1.52g of copper on reduction. The data above illustrates the law of?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">constant composition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">conservation of mass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reciprocal proportions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">multiple proportions</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The law of multiple proportions states that when two elements combine to form more than one compound, the weights of one element that combine with a fixed weight of the other are in a ratio of small whole numbers. The data given illustrates this law.</div>", "topic": "CHEMICAL COMBINATION : LAWS OF DEFINITE AND MULTIPLE PROPORTIONS"}, {"id": "objective>Chemistry>1997>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Use the graph above to answer this question. A sample, X, solid at room temperature, was melted, heated to a temperature of 358 K and allowed to cool as shown in OPQR. <br/>  <br/> The section PQ indicates that X is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a mixture of salts</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> a hydrated salt</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an ionic salt</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a pure compound</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The section PQ indicates that X is a pure compound because at PQ it is constant</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : PURE AND IMPURE SUBSTANCES"}, {"id": "objective>Chemistry>1997>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Use the graph above to answer this question. A sample, X, solid at room temperature, was melted, heated to a temperature of 358 K and allowed to cool as shown in OPQR.  <br/> The section OP suggests that X is in the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">liquid state</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> solid/liquid state</div>", "<div style=\"font-family:Cambria;font-size:17px;\">solid state</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gaseous state</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The section OP suggests that X is in the gaseous state</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : PURE AND IMPURE SUBSTANCES"}, {"id": "objective>Chemistry>1997>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An element, X, forms a volatile hydride XH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> with a vapour density of 17.0. The relative atomic mass of X is? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">34.0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">31.0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20.0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">14.0</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Molecular Mass = Vapour density x 2 = 17.0 x 2 = 34.0 <br/> ∴ Relative Atomic Mass of X in XH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> = 34 - 3 <br/> = 31.0 ∴ x = 31.0</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>1997>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A mixture of 0.20 mole of Ar, 0.20 mole of N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and 0.30 mole of He exerts a total pressure of 2.1 atm. The partial pressure of He in the mixture is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.90 atm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.80 atm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.70 atm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.60 atm</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Total no mole = 0.2 + 0.2 + 0.3 = 0.7 <br/> Partial pressure of He = (0.3)/(0.7) x 2.1 =0.90</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : THE LAWS OF BOYLE, CHARLES, GRAHAM AND DALTON LAW OF PARTIAL PRESSURE"}, {"id": "objective>Chemistry>1997>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If 30cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of oxygen diffuses through porous plug in 7s, how long will it take 60 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of chlorine to diffuse through the same plug?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">12s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">14s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">21s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">30s</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">(R)o/(R)a= √(M)a/(Mo (30/7)/(60/t) = √ (35.5)/(16) <br/> (60/t) (30/7)/ √(35.5)/(16) t = (60/30)/(7) x (4)√35.5 <br/> t = (60 x 7 x √35.5)/(30 x 4) = 21s</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : THE LAWS OF BOYLE, CHARLES, GRAHAM AND DALTON LAW OF PARTIAL PRESSURE"}, {"id": "objective>Chemistry>1997>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The temperature of a body decreases when drops of liquid placed on it evaporate because?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the atmospheric vapour pressure has a cooling effect on the body</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a temperature gradient exists between the drops of liquid and the body causing the latter to vaporate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the heat of vapourization is drawn from the body causing it to cool</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the random motion of the liquid molecules causes a cooling effect on the body</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a liquid evaporates, it absorbs heat from its surroundings. This heat is known as the heat of vaporization. The body cools down because it loses heat to the evaporating liquid.</div>", "topic": "ENERGY CHANGES : ENDOTHERMIC AND EXOTHERMIC REACTIONS"}, {"id": "objective>Chemistry>1997>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The electron configuration of two elements with similar chemical properties are represented by?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1S<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2S<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2P<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span> and 1S<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2S<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2P<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1S<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2S<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2P<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span> and 1S<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2S<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2P<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>3S<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1S<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2S<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2P<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>3S<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span> and 1S<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2S<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1S<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2S<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2P<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span> and 1S<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2S<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">They have the same number of electrons in the outermost shell which is 1</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>1997>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the periodic table, what is the property that decreases along the period and increases down the group?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Atomic number</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Electron affinity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ionization potential</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Atomic radius</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Atomic radius decreases along a period due to increasing nuclear charge which pulls the electrons closer to the nucleus. It increases down a group due to the addition of energy levels.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE PERIODIC TABLE AND PERIODICITY OF ELEMENTS"}, {"id": "objective>Chemistry>1997>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Two elements, P and Q with atomic numbers 11 and 8 respectively , combine chemically to form the compound PxQy. The respective values of x and y are?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1 and 1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1 and 2</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> 2 and 1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3 and 1</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The element with the atomic number 11 is sodium(Na) while the other with 8 is Oxygen(O2) <br/> The chemical reaction between the two element are as follow; <br/> 4Na+O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>---2Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O <br/> So according to the question p is sodium(Na) while q is Oxygen(O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>), <br/> While x and y are the subscript of sodium and oxygen respectively <br/> Hence the value of x=2 while y=1</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE CONCEPT OF ATOMS, MOLECULES AND IONS"}, {"id": "objective>Chemistry>1997>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Oxygen is a mixture of two isotopes <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">16</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span>O and <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">18</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span>O with relative abundances of 90% and 10% respectively. The relative atomic mass of oxygen is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">16.0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">16.2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">17.0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">18.0</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The relative atomic mass of an element is the weighted average of the atomic masses of its isotopes.  <br/> For Oxygen,  <br/> <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">16</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span>O=90%=0.9 <br/> <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">18</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span>O =10%=0.1 <br/> R.A.M=(0.9*16) + (0.1*18)  <br/> = 14.4 + 1.8 <br/> =16.2</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>1997>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">200 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of air was passed over heated copper in a syringe several times to produce copper (II) oxide. <br/> When cooled, the final volume of air recorded was 158cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>. Estimate the percentage of oxygen in the air?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> 31%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">27%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">21%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">19%</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The percentage of oxygen in the air can be calculated by the formula: (Initial volume - Final volume) / Initial volume * 100%. Therefore, (200cm^3 - 158cm^3) / 200cm^3 * 100% = 21%.</div>", "topic": "AIR : GASEOUS CONSTITUENTS"}, {"id": "objective>Chemistry>1997>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following gases is the most dangerous pollutant?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Hydrogen sulphide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Carbon (lV) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sulphur (lV) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Carbon (ll) oxide</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Carbon monoxide is a colourless, odourless and tasteless gas that is produced by the incomplete combustion of fossil fuel. It is the most dangerous of all the pollutant gases. It kills when inhaled in high concentration</div>", "topic": "ENVIRONMENTAL POLLUTION : AIR POLLUTION"}, {"id": "objective>Chemistry>1997>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major process involved in the softening of hard water is the?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> conversion of a soluble calcium salt to its trioxocarbonate (lV)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decomposition of calcium trioxocarbonate (lV)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">conversion of an insoluble calcium salts to its trioxocarbonate (lV)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxidation of calcium atoms to its ions</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is the conversion of soluble CaSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> to insoluble CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> by adding washing soda.In permanent hardness of water, when washing soda is treated with water, the carbonate ions from sodium carbonate react with calcium and magnesium ions in water and produce an insoluble product.</div>", "topic": "WATER : PURIFICATION OF TOWN WATER SUPPLIES"}, {"id": "objective>Chemistry>1997>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">On recrystallization, 20g of magnesium tetraoxosuphate (IV) forms 41 g of magnesium tetraoxosulphate (IV) crystals, MgSO4. yH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O. The value of y is? <br/> (Mg = 24, S = 32, O = 16, H = 1)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">MgSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>/MgSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>xH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O=mass of MgSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>/mass of MgSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>.xH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O <br/> 120/120+18x=20/41 <br/> 4920=2400+360x <br/> 4920-2400=360x <br/> 2520/360=x <br/> x=7</div>", "topic": "WATER : WATER OF CRYSTALLIZATION EFFLORESENCE DELIQUESCENCE AND HYGROSCOPY"}, {"id": "objective>Chemistry>1997>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A saturated solution of AgCl was found to have a concentration of 1.30 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span> mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>. The solubility product of AgCl therefore is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.30 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span> mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.30 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span>  mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span> <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.69 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-10</span>  mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span> <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.60 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-12</span>  mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span> <br/> </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The solubility product of AgCl is calculated by squaring the concentration of the saturated solution. Therefore, (1.30 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>)^2 = 1.69 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-10</span> mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>.</div>", "topic": "SOLUBILITY : SOLVENTS"}, {"id": "objective>Chemistry>1997>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The hydroxyl ion concentration, (OH<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span>), in a solution of sodium hydroxide of pH 10.0 is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-10</span> mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span> mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span> mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The pH of a solution is the negative logarithm of the hydrogen ion concentration. Therefore, the hydroxyl ion concentration, (OH<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span>), can be calculated using the formula pOH=14 - pH. So, 14 - 10 = 4. Therefore, the hydroxyl ion concentration is 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span> mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>.</div>", "topic": "ACID BASE AND SALTS : PH AND POH SCALE"}, {"id": "objective>Chemistry>1997>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the aqueous solutions with the pH values below will liberate hydrogen when it react with magnesium metals?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">13.0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7.0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.0</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Magnesium metal reacts with acids to produce hydrogen gas. Therefore, the solution with the lowest pH (most acidic) will react with magnesium to produce hydrogen. The solution with the lowest pH is 3.0.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>1997>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given that 15.00 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> was required to completely neutralize 25.00 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of 0.125 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> NaOH, calculate the molar concentration of the acid solution</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.925 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.156mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.104 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.023 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> <br/> </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> + 2NaOH → Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> + 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O <br/> (M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span>/(M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span> =n<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span>/n<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span>  <br/> (M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span> x 15)/(0.125 x25) = 1/2 <br/> (M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span> x 15) x 2 = (0.125 x25) x 1 <br/> 30M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span>= 3.125 <br/>  M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span> =3.125/30 <br/> M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span> = 0.104</div>", "topic": "ACID BASE AND SALTS : ACID AND BASE TITRATIONS"}, {"id": "objective>Chemistry>1997>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When platinum electrodes are used during the electrolysis of copper (ll) tetraoxosulphate (lV) solution, the solution gets progressively?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">acidic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">basic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">neutral</div>", "<div style=\"font-family:Cambria;font-size:17px;\">amphoteric</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">During the electrolysis of CuSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(aq)</span>, copper (ii) ions are reduced at the cathode as copper metal and hydroxide ions are oxidized at the anode as oxygen gas, leaving behind H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> and SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span> in solution, which combine to form H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> making the solution acidic.</div>", "topic": "ELECTROLYSIS : ELECTROLYTES AND NON-ELECTROLYTES"}, {"id": "objective>Chemistry>1997>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">How many Faradays of electricity are required to deposit 0.20 mole of nickel, if 0.10 Faraday of electricity deposited 2.98g of nickel during electrolysis of its aqueous solution? <br/> (Ni = 58.7, 1F = 96 500 C mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span>)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.20</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.30</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.40</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.50</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">n=m/Mm <br/> n=2.98/58.7 <br/> =0.05 <br/> Then <br/> 0.05m deposited 0.10faraday of electricity <br/> 0.05m----------0.10f <br/> 0.20m---------- X <br/> X=0.10×0.20/0.05 <br/> =0.4F</div>", "topic": "ELECTROLYSIS : FARADAY'S LAW OF ELECTROLYSIS"}, {"id": "objective>Chemistry>1997>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the oxidation number of Z in K<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>ZCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">-3</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> +3</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> -6</div>", "<div style=\"font-family:Cambria;font-size:17px;\">+6</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">K<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>ZCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>=0 <br/> (+3) + Z +(-1 * 6)=0 <br/> +3 + Z-6=0 <br/> Z=6-3=+3</div>", "topic": "OXIDATION AND REDUCTION : OXIDATION"}, {"id": "objective>Chemistry>1997>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + SO_2<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(I)</span> → 3S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + 3H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(I)</span>..........(i) 3CuO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + 2NH3<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> → 3Cu<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + 3H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(I)</span> + N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span>.........(II) In the equations above, the oxidizing agent (I) and the reducing agent in (II) respectively are?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S and NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and CuO</div>", "<div style=\"font-family:Cambria;font-size:17px;\">SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S and CuO</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> is the oxidizing agent because the oxidizing agent in a REDOX reaction is the substance whose oxidation number decreases in the positive direction. The oxidation number of S in SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> decrease from +4 to 0 in S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span> in equation (I) <br/>  <br/> While  NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> is the reducing agent because the reducing agent in a REDOX reaction is a substance whose oxidation number increases in the positive direction. In equation (II) the oxidation number of N in ammonia increases from -3 to 0 in nitrogen. </div>", "topic": "OXIDATION AND REDUCTION : REDUCTION"}, {"id": "objective>Chemistry>1997>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">2SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>(g) + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> → 2SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>. In the reaction above, the standard heats of formation of SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> and SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> are -297 KJ mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> and -396 kJ/mol respectively. The heat change of the reaction is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">-99 kJ mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">-198 kJ mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">+198 kJ mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">+683kJ mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">2SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> → 2SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> <br/> 2(-297) 2(-396) <br/> -594 -792 <br/> Heat change = heat of product - reactants = -792 - (-594) = -198kj mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span></div>", "topic": "ENERGY CHANGES : ENDOTHERMIC AND EXOTHERMIC REACTIONS"}, {"id": "objective>Chemistry>1997>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">2 </span>N2(g) + <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">2 </span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>(g) → NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> ∆H° 89 KJ mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>. If the entropy change for the reaction above at 25°C is 11.8 J mol-, calculate the change in free energy. ∆G°, for the reaction at 25°C?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">88.71 KJ</div>", "<div style=\"font-family:Cambria;font-size:17px;\">85.48 KJ</div>", "<div style=\"font-family:Cambria;font-size:17px;\">-204.00 KJ</div>", "<div style=\"font-family:Cambria;font-size:17px;\">-3427.40 KJ</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">∆G<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> = ∆H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> - T∆S<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>; T = 25° + 273 = 298 k <br/> ∆G<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>= 89 - (298 x 11.8)/ 1000 <br/> ∆G<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>= 89 - 3.5164 <br/> ∆G<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>=85.48 KJ</div>", "topic": "ENERGY CHANGES : SPONTANEITY OF REACTIONS"}, {"id": "objective>Chemistry>1997>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the rate law obtained for a given reaction is rate = k(X)n (Y)m, what is the overall order of the reaction?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">n/m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">n + m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">n - m</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The overall order of a reaction is the sum of the powers to which the concentration terms are raised in the rate equation. In this case, the overall order of the reaction is n + m.</div>", "topic": "RATE OF CHEMICAL REACTION : FACTORS"}, {"id": "objective>Chemistry>1997>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One method of driving the position of equilibrium of an endothermic reaction forward is to?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increase temperature at constant pressure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease pressure at constant temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cool down the apparatus with water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreases temperature at constant pressure</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">For an endothermic reaction, increasing the temperature will drive the equilibrium towards the products, thus moving the reaction forward.</div>", "topic": "CHEMICAL EQUILIBRA : FACTORS GOVERNING THE EQUILIBRIUM POSITION"}, {"id": "objective>Chemistry>1997>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Oxidation of concentrated hydrochloric acid with manganese (IV) oxide liberates a gas used in the?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">manufacture of tooth pastes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">treatment of simple goitre</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vulcanization of rubber</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sterilization of water</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The reaction of concentrated hydrochloric acid with manganese (IV) oxide liberates chlorine gas, which is used in the sterilization of water.</div>", "topic": "OXIDATION AND REDUCTION : OXIDATION"}, {"id": "objective>Chemistry>1997>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">mE + nF → pG + qH. In the equation, the equilibrium constant is given by?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">[E]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">m</span>[F]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">n</span>/[G]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">p</span>[H]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">q</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">[E][F]/[G][H]</div>", "<div style=\"font-family:Cambria;font-size:17px;\">[G]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">p</span>[H]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">q</span>/[E]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">m</span>[F]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">n</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">[G][H]/[E][F]</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The equilibrium constant (K) for a reaction is given by the ratio of the concentrations of the products to the concentrations of the reactants, each raised to the power of their stoichiometric coefficients. In this case, K = [G]^p[H]^q / [E]^m[F]^n.</div>", "topic": "CHEMICAL EQUILIBRA : DYNAMIC EQUILIBRIUM"}, {"id": "objective>Chemistry>1997>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A compound that will NOT produce oxygen on heating is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">potasium dioxonitrate (III)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lead (IV) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">potassium trioxochlorate (V)</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> potassium trioxonitrate (V)</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Potassium dioxonitrate (III) will not produce oxygen on heating because it does not contain any oxygen in its chemical structure.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>1997>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Coal gas is made up of carbon (II) oxide, hydrogen and?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nitrogen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">air</div>", "<div style=\"font-family:Cambria;font-size:17px;\">argon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">methane</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">coal gas, gaseous mixture—mainly hydrogen, methane, and carbon monoxide—formed by the destructive distillation (i.e., heating in the absence of air) of bituminous coal and used as a fuel.</div>", "topic": "AIR : GASEOUS CONSTITUENTS"}, {"id": "objective>Chemistry>1997>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> In the diagram above the gas Y could be </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hydrogen chloride</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxygen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon (IV) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chlorine</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Two gases that can be used in the study of fountain experiment is ammonia gas and hydrogen chloride gas.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>1997>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">2X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + MnO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + 4H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> → X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + Mn<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">l</span>. <br/> The reaction above can be used for the laboratory preparation of all halogens except fluorine because it is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a poisionous gas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an oxidizing agent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">electronegative in nature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">highly reactive</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The reaction cannot be used for the laboratory preparation of fluorine because fluorine is highly reactive.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>1997>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The reaction that occurs during the laboratory test for the presence of tetraoxosulphate (VI) ion is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">SO<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + Ba<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> → BaSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cu<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + 4H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + 2SO<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> → CuSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> + 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O + SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">4H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + 2SO<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span> + 2e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span>→  SO<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O + SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CuO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + 2H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + SO<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span>→ CuSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">l</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The reaction that occurs during the laboratory test for the presence of tetraoxosulphate (VI) ion is the precipitation reaction between tetraoxosulphate (VI) ions and barium tetraoxosulphate (VI) ions to form barium sulphate, a white precipitate.</div>", "topic": "ACID BASE AND SALTS : QUALITATIVE COMPARISON"}, {"id": "objective>Chemistry>1997>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The removal of rust from iron by treatment with tetraoxosulphate (IV) acid is based on the?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hydrolysis of the iron</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reaction of acid with base</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxidation of the rust</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dehydration of the iron</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The removal of rust from iron by treatment with tetraoxosulphate (IV) acid is based on the oxidation of the rust.</div>", "topic": "ACID BASE AND SALTS : ACID AND BASE TITRATIONS"}, {"id": "objective>Chemistry>1997>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the additives could improve the quality of steel?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Silicon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sulphur and phosphorus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Carbon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chromium and nickel</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The quality of steel can be improved by adding chromium and nickel, which increase its strength and resistance to corrosion.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALLOY"}, {"id": "objective>Chemistry>1997>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Sodium hydroxide is prepared commercially from sodium chloride solution by?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">electrolysis using mercury as cathode</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrolysis in steam using a catalyst</div>", "<div style=\"font-family:Cambria;font-size:17px;\">electrolysis using iron as anode</div>", "<div style=\"font-family:Cambria;font-size:17px;\">treating sodium chloride with ammonia and carbon (IV) oxide</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sodium hydroxide is prepared commercially from sodium chloride solution by electrolysis using mercury as cathode. This process is known as the Chloralkali process, where chlorine gas is produced at the anode, and sodium hydroxide is produced at the cathode.</div>", "topic": "ELECTROLYSIS : ELECTROLYTES AND NON-ELECTROLYTES"}, {"id": "objective>Chemistry>1997>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A sample of a substance containing only C and H burns in excess O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> to yield 4.4g of CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and 2.7 g of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O. The empirical formula of a substance is? <br/> (C = 12, O = 16, H = 1)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">x=Ar×m/M <br/> X=mass composition of the element <br/> Ar=R.M.M of the element <br/> m= mass if the product <br/> M=R.M.M of the product <br/> C=12/44 ×4.4=1.2g <br/> H=2/18×2.7=0.3g <br/> C <br/> 1.2/12 <br/> 0.1/0.1=1 <br/> H <br/> 0.3/1 <br/> 0.3/0.1=3 <br/> CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "topic": "CHEMICAL COMBINATION : STOICHIOMETRY"}, {"id": "objective>Chemistry>1997>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An undesirable paraffin in the petroleum industry which is particularly prone to knocking is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">iso-octane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">n-heptane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">iso-heptane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">n-octane</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">n-heptane is an undesirable paraffin in the petroleum industry which is particularly prone to knocking. Knocking is a phenomenon in spark-ignition internal combustion engines that occurs when combustion of some of the air/fuel mixture in the cylinder does not result from propagation of the flame front ignited by the spark plug, but one or more pockets of air/fuel mixture explode outside the envelope of the normal combustion front.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>1997>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The IUPAC nomenclature of the organic compound with the above structural formula is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3-ethyl-2,5-dimethylhexane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4-ethyl-2,5-dimethylhexane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3-ethyl, 1,1,4-trimethylpentane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3-ethyl-2,5,5 - trimethylpentane</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The IUPAC nomenclature of the organic compound with the above structural formula is 3-ethyl-2,5-dimethylhexane</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>1997>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The reaction of an alkanol with an alkanoic acid in the presence of concentrated H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> will produce an?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">alkanal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkanoate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkanone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkyne</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The reaction of an alkanol with an alkanoic acid in the presence of concentrated H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> will produce an alkanoate. This is a type of esterification reaction, where an alcohol reacts with a carboxylic acid to produce an ester and water.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOATES"}, {"id": "objective>Chemistry>1997>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The final product of the reaction of ethyne with hydrogen iodine is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>—CHI<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>I-CHI<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>—CI<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = CHI</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The final product of the reaction of ethyne with hydrogen iodine is CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>—CHI<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>. This is because ethyne (C_2)H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>) reacts with hydrogen iodide (HI) to add iodine atoms across the triple bond, resulting in the formation of an alkyl iodide.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>1997>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> How many more isomers of the compound above can be obtained ? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">4 more isomers of the compound above can be obtained </div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>1997>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Synthetic detergents are preferred to soap for laundry using hard water because?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> detergents are water soluble while soap is not</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the calcium salts of detergents are water soluble</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the magnesium salt of soap is soluble in hard water</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> soap does not have a hydrocarbon terminal chain</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Synthetic detergents are preferred to soap for laundry using hard water because the calcium salts of detergents are water soluble. Hard water contains calcium and magnesium ions, which react with soap to form insoluble precipitates, reducing the effectiveness of the soap. Detergents, on the other hand, form soluble salts with these ions, allowing them to remain effective in hard water.</div>", "topic": "WATER : PURIFICATION OF TOWN WATER SUPPLIES"}, {"id": "objective>Chemistry>1997>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The synthetic rubber obtained by the polymerization of chlorobutadiene in the presence of sodium is called?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">teflon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">isoprene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">polythene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">neoprene</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The synthetic rubber obtained by the polymerization of chlorobutadiene in the presence of sodium is called neoprene. Neoprene is a type of synthetic rubber that is resistant to oil, heat, and weathering.</div>", "topic": "ORGANIC COMPOUNDS : GIANT MOLECULES"}, {"id": "objective>Chemistry>1997>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">25 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of 0.02 M KOH neutralized 0.03 g of a monobasic organic acid having the general formula CnH2n + 1 COOH. The molecular formula of the acid is? <br/>  <br/> (C = 12, H = 1, O = 16)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">HCOOH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>COOH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span>COOH</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">n= C×V/1000 <br/> n= 0.02×25/1000 <br/> n=5×10-⁴moles <br/> n=m/M <br/> M=m/n <br/> M=0.03/0.0005=60g <br/> CnH2n+1COOH=60 <br/> 12n+2n+1+12+16+16+1=60 <br/> 14n+46=60 <br/> 14n=60-46=14 <br/> n=14/14=1 <br/> CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOH</div>", "topic": "ACID BASE AND SALTS : ACID AND BASE TITRATIONS"}, {"id": "objective>Chemistry>1997>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Choose the correct answer from the options above. When Fehling's solution is added to two isomeric carbonyl compounds X and Y with the molecular formula C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span>O, compound X gives a red precipitate while Y does not react. It can be inferred that X is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">B</div>", "<div style=\"font-family:Cambria;font-size:17px;\">C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">D</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fehling's solution is used to differentiate between aldehydes and ketones. Aldehydes will reduce Fehling's solution, producing a red precipitate of copper(I) oxide, while ketones generally do not react. Given that compound X reacts Fehling's solution to give a red precipitate, it can be inferred that compound X is an aldehyde. Compound Y, which does not react is likely a ketone.</div>", "topic": "ORGANIC COMPOUNDS : ALKANALS AND ALKANONES"}, {"id": "objective>Chemistry>1997>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The compound above contains</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Sp<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> hybridized carbon atoms only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sp<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> hybridized carbon atoms only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sp<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> and Sp hybirdized carbon atoms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sp<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> and Sp<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The structure of the compound above contains Sp<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> and Sp<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>1997>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The compound above is the product of the oxidation of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2-methlbutan-2-ol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2-methylbutan -1- ol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2, 3-dimethylpropan-1-ol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pentan -2- ol</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">2-methylbutan -1- ol is a primary alkanol. Primary alkanols are first oxidized to alkanal and alkanoic acid also known as carboxylic acid.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}];
